parameters.jsCode:
// Parse Groq's text response into a real JSON object
const groqResponse = JSON.parse($input.first().json.choices[0].message.content);

const nextTask = groqResponse.call_agent === "Template Agent" ? "Email" : "None";

// Create the single result
const singleResult = {
  call_agent: groqResponse.call_agent,
  task_type: nextTask,
  log_entry: groqResponse.log_entry,
  sop_checklist: groqResponse.sop_checklist
};

// Clone it 5 times to satisfy the Orchestrator's loop
return [1, 2, 3, 4, 5].map(iterationNumber => ({ 
    json: singleResult 
}));
